const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');
const { SecretManagerServiceClient } = require('@google-cloud/secret-manager');

const secretClient = new SecretManagerServiceClient();

async function accessSecretVersion(name) {
  const [version] = await secretClient.accessSecretVersion({ name });
  return version.payload.data.toString('utf8');
}

let sendGridApiKey, twilioAccountSid, twilioAuthToken, twilioPhoneNumber;

async function initializeSecrets() {
  if (!sendGridApiKey) {
    sendGridApiKey = await accessSecretVersion('projects/YOUR_PROJECT_ID/secrets/SENDGRID_API_KEY/versions/latest');
    sgMail.setApiKey(sendGridApiKey);
  }
  if (!twilioAccountSid || !twilioAuthToken || !twilioPhoneNumber) {
    twilioAccountSid = await accessSecretVersion('projects/YOUR_PROJECT_ID/secrets/TWILIO_ACCOUNT_SID/versions/latest');
    twilioAuthToken = await accessSecretVersion('projects/YOUR_PROJECT_ID/secrets/TWILIO_AUTH_TOKEN/versions/latest');
    twilioPhoneNumber = await accessSecretVersion('projects/YOUR_PROJECT_ID/secrets/TWILIO_PHONE_NUMBER/versions/latest');
  }
}

functions.http('sendNotification', async (req, res) => {
  try {
    await initializeSecrets();

    const { email, subject, text, phoneNumber, message } = req.body;

    if (email && subject && text) {
      const msg = {
        to: email,
        from: 'your-email@example.com',
        subject: subject,
        text: text,
      };
      await sgMail.send(msg);
    }

    if (phoneNumber && message) {
      const client = twilio(twilioAccountSid, twilioAuthToken);
      await client.messages.create({
        body: message,
        from: twilioPhoneNumber,
        to: phoneNumber,
      });
    }

    res.status(200).send('Notifications sent successfully.');
  } catch (error) {
    console.error('Error sending notifications:', error);
    res.status(500).send('Error sending notifications.');
  }
});